import openai
import json
from typing import Callable

client = openai.OpenAI()

# === Example 1: Simple Tool Use with OpenAI Function Calling ===
print("=== Tool Use (Function Calling) ===")

def get_weather(city: str) -> str:
    """Simulate getting weather data for a city."""
    weather_data = {
        "New York": {"temp": 72, "condition": "Sunny", "humidity": 45},
        "London": {"temp": 58, "condition": "Cloudy", "humidity": 78},
        "Tokyo": {"temp": 68, "condition": "Partly Cloudy", "humidity": 60},
    }
    data = weather_data.get(city, {"temp": 70, "condition": "Unknown", "humidity": 50})
    return json.dumps(data)

def calculate(expression: str) -> str:
    """Evaluate a mathematical expression safely."""
    try:
        result = eval(expression, {"__builtins__": {}})
        return json.dumps({"result": result})
    except Exception as e:
        return json.dumps({"error": str(e)})

tools = [
    {
        "type": "function",
        "function": {
            "name": "get_weather",
            "description": "Get current weather for a city",
            "parameters": {
                "type": "object",
                "properties": {
                    "city": {"type": "string", "description": "City name"}
                },
                "required": ["city"]
            }
        }
    },
    {
        "type": "function",
        "function": {
            "name": "calculate",
            "description": "Evaluate a math expression",
            "parameters": {
                "type": "object",
                "properties": {
                    "expression": {"type": "string", "description": "Math expression"}
                },
                "required": ["expression"]
            }
        }
    }
]

available_functions = {"get_weather": get_weather, "calculate": calculate}

response = client.chat.completions.create(
    model="gpt-4o",
    messages=[{"role": "user", "content": "What's the weather in Tokyo and what's 15% of that temperature in Celsius?"}],
    tools=tools,
    tool_choice="auto"
)

assistant_message = response.choices[0].message
print(f"Model wants to call: {assistant_message.tool_calls}")

# Execute tool calls
if assistant_message.tool_calls:
    messages = [{"role": "user", "content": "What's the weather in Tokyo and what's 15% of that temperature in Celsius?"}]
    messages.append(assistant_message)

    for tool_call in assistant_message.tool_calls:
        function_name = tool_call.function.name
        function_args = json.loads(tool_call.function.arguments)
        function_result = available_functions[function_name](**function_args)
        print(f"  {function_name}({function_args}) = {function_result}")
        messages.append({
            "role": "tool",
            "tool_call_id": tool_call.id,
            "content": function_result
        })

    final_response = client.chat.completions.create(
        model="gpt-4o",
        messages=messages
    )
    print(f"Final answer: {final_response.choices[0].message.content}")

# === Example 2: ReAct Agent Loop ===
print("\n=== ReAct Agent Loop ===")

def react_agent(query: str, max_steps: int = 5) -> str:
    """Simple ReAct agent implementation."""
    system_prompt = """You are a helpful assistant that uses tools to answer questions.

Available tools:
- search_web(query): Search the internet
- calculate(expression): Do math
- get_weather(city): Get weather

Format your response as:
Thought: [your reasoning]
Action: tool_name
Action Input: {"arg": "value"}

When you have the final answer:
Thought: I now have enough information
Final Answer: [your answer]"""

    messages = [
        {"role": "system", "content": system_prompt},
        {"role": "user", "content": query}
    ]

    for step in range(max_steps):
        response = client.chat.completions.create(
            model="gpt-4o",
            messages=messages,
            temperature=0
        )
        assistant_msg = response.choices[0].message.content
        print(f"Step {step + 1}:\n{assistant_msg}\n")

        if "Final Answer:" in assistant_msg:
            return assistant_msg.split("Final Answer:")[1].strip()

        messages.append({"role": "assistant", "content": assistant_msg})
        messages.append({"role": "user", "content": "Continue with the next step."})

    return "Agent reached maximum steps without completing the task."

# Test the agent
result = react_agent("What is 25 * 47 + 123?")
print(f"Agent result: {result}")
